CREATE PROCEDURE ExampleProc (IN I INTEGER)
{
  DECLARE STR, STR2 VARCHAR;
  RESULT_NAMES (I, STR);
  RESULT (1, 'Alice');
  RESULT (2, 'Bob');
  RETURN 1;
};

CREATE PROCEDURE ComplexProc (IN I INTEGER)
{
  DECLARE STR1, STR2 VARCHAR;
  DECLARE TempID INTEGER;
  RESULT_NAMES (I, STR1, STR2);
  SET TempID = (SELECT MAX(ID) FROM TestTable);
  RESULT (TempID, 'Max ID');
  RESULT_NAMES (I, STR1, STR2);
  END_RESULT ();
  RESULT (1, 'Result 1');
  RETURN 1;
};

CREATE PROCEDURE JoinProc (IN I INTEGER)
{
  DECLARE STR1, STR2 VARCHAR;
  RESULT_NAMES (I, STR1, STR2);
  RESULT (1, 'Combined Result 1');
  END_RESULT ();
  RESULT (2, 'Combined Result 2');
  RETURN 1;
};

CREATE PROCEDURE NestedProc (IN I INTEGER)
{
  DECLARE STR VARCHAR;
  RESULT_NAMES (I, STR);
  RESULT ((SELECT COUNT(*) FROM TestTable), 'Row Count');
  RESULT (I + 1, 'Next Result');
  END_RESULT ();
  RESULT (I + 2, 'Another Result');
  RETURN 1;
};

CREATE PROCEDURE FinalProc (IN I INTEGER)
{
  DECLARE STR, STR2, STR3 VARCHAR;
  RESULT_NAMES (I, STR, STR2);
  RESULT (I, 'First Result');
  END_RESULT ();
  RESULT_NAMES (I, STR, STR2, STR3);
  RESULT (I + 1, 'Second Result', 'Extra Info');
  RESULT (I + 2, 'Third Result');
  RETURN 1;
};
